def parse_args():
    parser = argparse.ArgumentParser(
        description="Test VLA Diffusion Policy with all Success Parameter Sets from CMA-ES"
    )
    parser.add_argument("--checkpoint", type=str, default="checkpoints/fm_bottleneck_model.pt")
    parser.add_argument("--env-name", type=str, default="pick-place-v3")
    parser.add_argument("--seed", type=int, default=42)
    parser.add_argument("--episodes", type=int, default=100,
                       help="Episodes per Success set (default: 100)")
    parser.add_argument("--max-steps", type=int, default=150)
    parser.add_argument("--instruction", type=str, default="pick and place the object to the goal")
    parser.add_argument("--device", type=str, default="cpu")
    parser.add_argument("--robot", type=str, default="sawyer", choices=["sawyer", "ur10e"])
    parser.add_argument("--save-video", action="store_true",
                       help="Save and log one rollout video per Success set")
    parser.add_argument("--video-fps", type=int, default=30,
                       help="FPS used when writing videos")
    parser.add_argument("--video-episode-index", type=int, default=0,
                       help="Which episode index (0-based) to record per Success set")
    parser.add_argument("--no-wandb", action="store_true")
    return parser.parse_args()


def load_model_and_tokenizer(checkpoint_path: str, device: torch.device):
    """Load the trained VLA model and tokenizer."""
    ckpt = torch.load(checkpoint_path, map_location=device)
    vocab = ckpt["vocab"]
    state_dim = ckpt["state_dim"]
    action_dim = ckpt["action_dim"]
    d_model = ckpt["d_model"]
    diffusion_T = ckpt["diffusion_T"]
    vocab_size = max(vocab.values()) + 1

    model = VLADiffusionPolicy(
        vocab_size=vocab_size,
        state_dim=state_dim,
        action_dim=action_dim,
        d_model=d_model,
        diffusion_T=diffusion_T,
    ).to(device)

    model.load_state_dict(ckpt["model_state_dict"])
    model.eval()
    tokenizer = SimpleTokenizer(vocab=vocab)
    return model, tokenizer


def _parse_slice(s: str) -> slice:
    """Parse a string like '0:1' to slice(0, 1)."""
    parts = s.split(":")
    if len(parts) == 1:
        i = int(parts[0])
        return slice(i, i + 1)
    return slice(*[int(p) if p else None for p in parts])


def _build_array(d_model: int, default: float, spec: Dict) -> np.ndarray:
    """Build parameter array from dictionary specification."""
    arr = np.full(d_model, default, dtype=np.float32)
    if isinstance(spec, dict):
        for key, val in spec.items():
            arr[_parse_slice(key)] = float(val)
    return arr


def get_film_params_from_dict(d_model: int, param_dict: Dict) -> Tuple[torch.Tensor, torch.Tensor]:
    """Extract gamma and beta tensors from parameter dictionary."""
    gamma_arr = _build_array(d_model, 1.0, param_dict.get("gamma", {}))
    beta_arr = _build_array(d_model, 0.0, param_dict.get("beta", {}))
    return torch.tensor(gamma_arr, dtype=torch.float32), torch.tensor(beta_arr, dtype=torch.float32)


def run_episode_with_modulation(model, env, text_ids, device, max_steps, gamma, beta, record_video=False):
    """
    Run a single episode using the diffusion model with FiLM modulation.
    """
    img, state, info = env.reset()
    step = 0
    ep_reward = 0.0
    success = False
    
    gamma = gamma.to(device).unsqueeze(0)  # (1, d_model)
    beta = beta.to(device).unsqueeze(0)    # (1, d_model)

    done = False
    frames = []
    if record_video:
        frames.append(img.copy())

    while not done and step < max_steps:
        img_t = torch.from_numpy(img).permute(2, 0, 1).float().unsqueeze(0) / 255.0
        state_t = torch.from_numpy(state).float().unsqueeze(0)

        img_t = img_t.to(device)
        state_t = state_t.to(device)

        with torch.no_grad():
            action = model.act(img_t, text_ids, state_t, gamma, beta)

        action_np = action.squeeze(0).cpu().numpy()
        img, state, reward, done, info = env.step(action_np)
        ep_reward = reward
        step += 1

        if record_video:
            frames.append(img.copy())

        if info.get('success', False):
            success = True
            done = True

    return ep_reward, step, success, frames


def evaluate_success_set(success_num: int, param_dict: Dict, model, env, text_ids, device, args) -> Dict:
    """
    Evaluate one Success parameter set over multiple episodes.
    Returns statistics.
    """
    gamma, beta = get_film_params_from_dict(16, param_dict)
    
    rewards = []
    successes = 0
    steps_list = []
    video_logged = False

    print(f"\n{'='*70}")
    print(f"Success #{success_num}: Running {args.episodes} episodes")
    print(f"{'='*70}")

    for ep in range(args.episodes):
        should_record_video = args.save_video
        reward, steps, success, frames = run_episode_with_modulation(
            model, env, text_ids, device, args.max_steps, gamma, beta, record_video=should_record_video
        )
        rewards.append(reward)
        steps_list.append(steps)
        if success:
            successes += 1

        if not args.no_wandb:
            wandb.log({
                "Episode": ep + 1,
                "eval/reward": reward,
                "eval/success": int(success),
            }, step=ep + 1)

        if should_record_video and frames:
            if not args.no_wandb:
                with tempfile.NamedTemporaryFile(suffix=".mp4", delete=True) as tmp:
                    with imageio.get_writer(tmp.name, fps=args.video_fps) as writer:
                        for frame in frames:
                            frame_rot = np.rot90(frame, 2)
                            writer.append_data(frame_rot)

                    wandb.log({
                        f"eval/video": wandb.Video(tmp.name, format="mp4")
                    })
                video_logged = True

        if (ep + 1) % 10 == 0:
            current_success_rate = successes / (ep + 1)
            print(f"  Episode {ep+1:3d}/{args.episodes} | "
                  f"Success Rate: {current_success_rate:.2%} ({successes}/{ep+1})")

    mean_reward = np.mean(rewards)
    std_reward = np.std(rewards)
    mean_steps = np.mean(steps_list)
    success_rate = successes / args.episodes

    result = {
        "success_num": success_num,
        "total_episodes": args.episodes,
        "successes": successes,
        "success_rate": success_rate,
        "mean_reward": mean_reward,
        "std_reward": std_reward,
        "mean_steps": mean_steps,
        "gamma": param_dict["gamma"],
        "beta": param_dict["beta"],
        "video_logged": video_logged,
    }

    print(f"\nSuccess #{success_num} Results:")
    print(f"{'='*70}")

    return result


def main():
    args = parse_args()

    device = torch.device("cuda" if (args.device == "cuda" and torch.cuda.is_available()) else "cpu")
    print(f"Using device: {device}")

    # Load model and tokenizer
    print("Loading model and tokenizer...")
    model, tokenizer = load_model_and_tokenizer(args.checkpoint, device)

    # Encode instruction
    text_tokens = tokenizer.encode(args.instruction)
    text_ids = torch.tensor(text_tokens, dtype=torch.long).unsqueeze(0).to(device)

    # Create environment
    if args.robot == "sawyer":
        env = MetaWorldMT1Wrapper(
            env_name=args.env_name,
            seed=args.seed,
            render_mode="rgb_array",
            camera_name="corner2",
            random_init=True,
        )
    elif args.robot == "ur10e":
        env = UR10ePickPlaceEnvV3(
            render_mode="rgb_array",
            camera_name="corner2",
            seed=args.seed,
            random_init=False,
        )

    # Evaluate all Success parameter sets
    all_results = []
    
    print(f"\n{'='*70}")
    print(f"EVALUATING {len(SUCCESS_PARAM_SETS)} SUCCESS PARAMETER SETS")
    print(f"Each set: {args.episodes} episodes")
    print(f"Total episodes: {len(SUCCESS_PARAM_SETS) * args.episodes}")
    print(f"{'='*70}")

    for success_num in sorted(SUCCESS_PARAM_SETS.keys()):
        param_dict = SUCCESS_PARAM_SETS[success_num]

        #env.reset_episode_count()

        if not args.no_wandb:
            run_name = f"success_set_{success_num:02d}_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            wandb.init(
                entity="kaitos_projects",
                project="VLA_CMA_ES_All_Success_Sets_3",
                name=run_name,
                reinit=True,
                group="success_sets_eval",
                config={
                    "env_name": args.env_name,
                    "episodes_per_set": args.episodes,
                    "max_steps": args.max_steps,
                    "num_success_sets": len(SUCCESS_PARAM_SETS),
                    "success_set": success_num,
                    "robot": args.robot,
                    "checkpoint": args.checkpoint,
                    "instruction": args.instruction,
                    "save_video": args.save_video,
                },
            )

        result = evaluate_success_set(success_num, param_dict, model, env, text_ids, device, args)
        all_results.append(result)

    # Sort by success rate
    sorted_results = sorted(all_results, key=lambda x: x["success_rate"], reverse=True)

    print(f"\n{'='*70}")
    print(f"Best Performing Set: Success #{sorted_results[0]['success_num']}")
    print(f"{'='*70}")

    env.close()


if __name__ == "__main__":
    main()